mapper.select:
SELECT boardId, boardName, boardType, description, allowComment, allowAttach, allowAnonymous, allowSearch, readRole, writeRole, listCount, newDays, sortOrder, useYn, createdUser, createdDate, updateUser, updatedDate FROM board_master
AND boardName LIKE CONCAT('%', #{boardName}, '%')
AND boardType = #{boardType}
AND useYn = #{useYn}
ORDER BY sortOrder, boardId
